import { z } from "zod";

import { colors } from "$lib/registry/registry-colors.js";

const colorSchema = z.object({
	name: z.string(),
	id: z.string(),
	scale: z.number(),
	class: z.string(),
	hex: z.string(),
	rgb: z.string(),
	hsl: z.string(),
	foreground: z.string(),
	oklch: z.string(),
	var: z.string(),
});

const colorPaletteSchema = z.object({
	name: z.string(),
	colors: z.array(colorSchema),
});

export type ColorPalette = z.infer<typeof colorPaletteSchema>;

type ColorFormat = {
	class: string;
	hex: string;
	rgb: string;
	hsl: string;
	oklch: string;
	var: string;
};

export function getColorFormat(color: Color): ColorFormat {
	return {
		class: `bg-${color.name}-100`,
		hex: color.hex,
		rgb: color.rgb,
		hsl: color.hsl,
		oklch: color.oklch,
		var: `--color-${color.name}-${color.scale}`,
	};
}

export function getColors(): ColorPalette[] {
	const tailwindColors = colorPaletteSchema.array().parse(
		Object.entries(colors)
			.map(([name, color]) => {
				if (!Array.isArray(color)) {
					return null;
				}

				return {
					name,
					colors: color.map((color) => {
						const rgb = color.rgb.replace(/^rgb\((\d+),(\d+),(\d+)\)$/, "$1 $2 $3");

						return {
							...color,
							name,
							id: `${name}-${color.scale}`,
							class: `${name}-${color.scale}`,
							var: `--color-${name}-${color.scale}`,
							rgb,
							hsl: color.hsl.replace(
								/^hsl\(([\d.]+),([\d.]+%),([\d.]+%)\)$/,
								"$1 $2 $3"
							),
							oklch: `oklch(${color.oklch.replace(
								/^oklch\(([\d.]+)\s*,\s*([\d.]+)\s*,\s*([\d.]+)\)$/,
								"$1 $2 $3"
							)})`,
							foreground: getForegroundFromBackground(rgb),
						};
					}),
				};
			})
			.filter(Boolean)
	);

	return tailwindColors;
}

export type Color = ReturnType<typeof getColors>[number]["colors"][number];

function getForegroundFromBackground(rgb: string): string {
	const [r, g, b] = rgb.split(" ").map(Number);

	function toLinear(number: number): number {
		const base = number / 255;
		return base <= 0.04045 ? base / 12.92 : Math.pow((base + 0.055) / 1.055, 2.4);
	}

	const luminance = 0.2126 * toLinear(r) + 0.7152 * toLinear(g) + 0.0722 * toLinear(b);

	return luminance > 0.179 ? "#000" : "#fff";
}

function updateThemePlugin(ast: Root, cssVars: CssVars): void {
	const variables = Array.from(
		new Set(
			Object.keys(cssVars).flatMap((key) =>
				Object.keys((cssVars as Record<string, Record<string, string>>)[key] ?? {})
			)
		)
	);

	if (variables.length === 0) return;

	const themeNode = upsertThemeNode(ast);

	const themeVarNodes = themeNode.nodes?.filter(
		(node): node is Declaration => node.type === "decl" && node.prop.startsWith("--")
	);

	for (const variable of variables) {
		const value = Object.values(cssVars).find((vars) => vars?.[variable])?.[variable];

		if (!value) continue;

		if (variable === "radius") {
			const radiusVariables: Record<string, string> = {
				sm: "calc(var(--radius) * 0.6)",
				md: "calc(var(--radius) * 0.8)",
				lg: "var(--radius)",
				xl: "calc(var(--radius) * 1.4)",
				"2xl": "calc(var(--radius) * 1.8)",
				"3xl": "calc(var(--radius) * 2.2)",
				"4xl": "calc(var(--radius) * 2.6)",
			};
			for (const [key, radiusValue] of Object.entries(radiusVariables)) {
				const cssVarNode = postcss.decl({
					prop: `--radius-${key}`,
					value: radiusValue,
					raws: { semicolon: true },
				});
				if (
					themeNode.nodes?.find(
						(node): node is Declaration =>
							node.type === "decl" && node.prop === cssVarNode.prop
					)
				) {
					continue;
				}
				themeNode.append(cssVarNode);
			}
			continue;
		}

		let prop =
			isLocalHSLValue(value) || isColorValue(value)
				? `--color-${variable.replace(/^--/, "")}`
				: `--${variable.replace(/^--/, "")}`;
		if (prop === "--color-sidebar-background") {
			prop = "--color-sidebar";
		}

		let propValue = `var(--${variable})`;
		if (prop === "--color-sidebar") {
			propValue = "var(--sidebar)";
		}

		const cssVarNode = postcss.decl({
			prop,
			value: propValue,
			raws: { semicolon: true },
		});
		const existingDecl = themeNode.nodes?.find(
			(node): node is Declaration => node.type === "decl" && node.prop === cssVarNode.prop
		);
		if (!existingDecl) {
			if (themeVarNodes && themeVarNodes.length > 0) {
				themeNode.insertAfter(themeVarNodes[themeVarNodes.length - 1]!, cssVarNode);
			} else {
				themeNode.append(cssVarNode);
			}
		}
	}
}
